import React, { useState, useEffect } from "react";
import BMI from "./BMI";
import AITrainer from "./AITrainer";
import AIChatbot from "./AIChatbot";
import Recommendation from "./Recommendation";
import Progress from "./Progress";
import "../styles/dashboard.css";

function Dashboard({ activeSection }) {
  const [profileName, setProfileName] = useState(
    localStorage.getItem("profileName") || "Yash Gupta"
  );

  const [profileGoal, setProfileGoal] = useState(
    localStorage.getItem("profileGoal") || "Better Health"
  );

  useEffect(() => {
    localStorage.setItem("profileName", profileName);
    localStorage.setItem("profileGoal", profileGoal);
  }, [profileName, profileGoal]);

  function updateProfile() {
    const newName = prompt("Enter your name:", profileName);
    const newGoal = prompt("Enter your fitness goal:", profileGoal);

    if (newName) setProfileName(newName);
    if (newGoal) setProfileGoal(newGoal);
  }

  const profileCard = (
    <div className="profile-card single-section-card">
      <div className="profile-avatar">
        {profileName
          .split(" ")
          .map((part) => part[0])
          .join("")
          .slice(0, 2)
          .toUpperCase()}
      </div>

      <h3>{profileName}</h3>
      <p>{profileGoal}</p>

      <div className="profile-meta">
        <span>🎯 Goal: {profileGoal}</span>
        <span>⚡ Mode: Active</span>
      </div>

      <button className="profile-btn" onClick={updateProfile}>
        Edit Profile
      </button>
    </div>
  );

  const workoutPlans = (
    <div className="workout-plan-card single-section-card">
      <h3>Workout Plans</h3>

      <div className="workout-grid">
        <div className="workout-item">
          <div className="workout-icon">🔥</div>
          <div>
            <h4>Fat Burn</h4>
            <p>Cardio + light HIIT routine</p>
          </div>
        </div>

        <div className="workout-item">
          <div className="workout-icon">🧘</div>
          <div>
            <h4>Stress Relief</h4>
            <p>Breathing + meditation plan</p>
          </div>
        </div>

        <div className="workout-item">
          <div className="workout-icon">🦵</div>
          <div>
            <h4>Knee Care</h4>
            <p>Mobility and stretch routine</p>
          </div>
        </div>

        <div className="workout-item">
          <div className="workout-icon">💤</div>
          <div>
            <h4>Sleep Reset</h4>
            <p>Relaxation and calm-down plan</p>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <main className="dashboard-main">
      {activeSection === "dashboard" && (
        <>
          <section className="hero-section">
            <div className="hero-content">
              <p className="hero-badge">AI Powered Fitness • Smart Health Guidance</p>

              <h1 className="hero-title">
                Smart Health & Fitness Recommender
              </h1>

              <p className="hero-subtitle">
                BMI, AI advice, chatbot support, exercise videos, workout plans,
                and progress tracking in one dashboard.
              </p>
            </div>
          </section>

          <section className="stats-row">
            <div className="stat-card">
              <h3>25+</h3>
              <p>Health Issues</p>
            </div>

            <div className="stat-card">
              <h3>AI</h3>
              <p>Smart Support</p>
            </div>

            <div className="stat-card">
              <h3>20+</h3>
              <p>Exercise Videos</p>
            </div>

            <div className="stat-card">
              <h3>100%</h3>
              <p>Mobile Ready</p>
            </div>
          </section>

          <section className="profile-workout-row">
            {profileCard}
            {workoutPlans}
          </section>

          <div className="container">
            <BMI />
            <AITrainer />
            <AIChatbot />
            <Recommendation />
            <Progress />
          </div>
        </>
      )}

      {activeSection === "bmi" && (
        <div className="container">
          <h1 className="title">BMI Tracker</h1>
          <BMI />
        </div>
      )}

      {activeSection === "trainer" && (
        <div className="container">
          <h1 className="title">AI Fitness Trainer</h1>
          <AITrainer />
        </div>
      )}

      {activeSection === "chatbot" && (
        <div className="container">
          <h1 className="title">AI Fitness Chatbot</h1>
          <AIChatbot />
        </div>
      )}

      {activeSection === "recommendation" && (
        <div className="container">
          <h1 className="title">Exercise Recommendations</h1>
          <Recommendation />
        </div>
      )}

      {activeSection === "progress" && (
        <div className="container">
          <h1 className="title">Workout Progress</h1>
          <Progress />
        </div>
      )}

      {activeSection === "profile" && (
        <div className="container">
          <h1 className="title">Profile Card</h1>
          {profileCard}
        </div>
      )}

      {activeSection === "plans" && (
        <div className="container">
          <h1 className="title">Workout Plans</h1>
          {workoutPlans}
        </div>
      )}
    </main>
  );
}

export default Dashboard;
